
document.addEventListener("DOMContentLoaded",function(){const popularItems=document.querySelector('#popular-items__container'),hoverItemClass='popular-item';let timer=null;popularItems.addEventListener('mouseover',mouseOverAndOutCardHandler);document.addEventListener("mouseover",checkHoverCardsHandler);popularItems.addEventListener('mouseout',mouseOverAndOutCardHandler);function mouseOverAndOutCardHandler(evt){const hoveredItem=evt.target.closest('.'+hoverItemClass);if(hoveredItem!==undefined&&hoveredItem!==null){switch(evt.type){case'mouseover':if(evt.target.closest('.popular-items')!==null){if(hoveredItem.classList.contains('hover-card')){clearTimeout(timer);return;}else{resetAllHover();}}
timer=setTimeout(function(){hoveredItem.classList.add('current');hoveredItem.classList.add('hover-card');},500);break;case'mouseout':clearTimeout(timer);if(!hoveredItem.classList.contains('hover-card')){clearTimeout(timer);resetAllHover();}
break;}}}
function clickCardCardHandler(evt){const hoveredItem=evt.target.closest('.'+hoverItemClass);if(hoveredItem.classList.contains('hover-card')){hoveredItem.classList.remove('hover-card');hoveredItem.classList.remove('current');}
else{hoveredItem.classList.add('hover-card');hoveredItem.classList.add('current');}}
function checkHoverCardsHandler(evt){if(evt.target.closest('#popular-items__container')===null){resetAllHover();}}
function resetAllHover(){document.querySelectorAll('.hover-card').forEach(function(item){item.classList.remove('hover-card');item.classList.remove('current');});}});



document.addEventListener("DOMContentLoaded",function(){const burger=document.querySelector('#burger'),navList=document.querySelector('#nav-list'),overlay=document.querySelector('#overlay'),lastLineBurger=document.querySelector('.line-3');if(issetItem(burger)){burger.addEventListener('click',openAndCloseMenu);}
function openAndCloseMenu(e){if(issetItem(overlay)){overlay.classList.toggle('active');navList.classList.toggle('active');burger.classList.toggle('clicked-js');if(navList.classList.contains('active')){document.body.classList.add('lock');}else{document.body.classList.remove('lock');}
makeCloseButtonFromBurger();}}
function issetItem(item){if(item!==null&&item!==undefined)return true;return false;}
function makeCloseButtonFromBurger(){if(burger.classList.contains('clicked-js')){lastLineBurger.style.display='none';}else{lastLineBurger.style.display='block';}}});

import Swiper from"https://cdn.jsdelivr.net/npm/swiper@10/swiper-bundle.min.mjs";document.addEventListener("DOMContentLoaded",function(){const swiper=new Swiper('.popular-slider',{slidesPerView:2,slidesPerGroup:1,centeredSlides:true,initialSlide:1,breakpoints:{1200:{slidesPerView:3,},768:{slidesPerView:2,spaceBetween:0,},576:{slidesPerView:1,},540:{slidesPerView:1,},320:{slidesPerView:1,},}});})